   166→// ============================================================================
   167→// Saddle - Return context needed to saddle up on a Heat
   168→// ============================================================================
   169→
   170→/// Arguments for saddle command
   171→#[derive(Debug)]
   172→pub struct jjrq_SaddleArgs {
   173→    pub file: std::path::PathBuf,
   174→    pub firemark: Firemark,
   175→}
   176→
   177→/// Run the saddle command - return Heat context
   178→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
   179→    let gallops = match Gallops::jjrg_load(&args.file) {
   180→        Ok(g) => g,
   181→        Err(e) => {
   182→            eprintln!("jjx_saddle: error: {}", e);
   183→            return 1;
   184→        }
   185→    };
   186→
   187→    let heat_key = args.firemark.jjrf_display();
   188→    let heat = match gallops.heats.get(&heat_key) {
   189→        Some(h) => h,
   190→        None => {
   191→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   192→            return 1;
   193→        }
   194→    };
   195→
   196→    // Check if heat is stabled (cannot saddle stabled heat)
   197→    if heat.status == HeatStatus::Stabled {
   198→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
   199→        return 1;
   200→    }
   201→
   202→    // Read paddock file content
   203→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   204→        Ok(content) => content,
   205→        Err(e) => {
   206→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   207→            return 1;
   208→        }
   209→    };
   210→
   211→    // Get recent steeplechase entries
   212→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   213→        firemark: args.firemark.jjrf_as_str().to_string(),
   214→        limit: 10,
   215→    }).unwrap_or_default();
   216→
   217→    // Find first actionable pace (rough or bridled)
   218→    let mut pace_coronet: Option<String> = None;
   219→    let mut pace_silks: Option<String> = None;
   220→    let mut pace_state: Option<String> = None;
   221→    let mut spec: Option<String> = None;
   222→    let mut direction: Option<String> = None;
   223→
   224→    for coronet_key in &heat.order {
   225→        if let Some(pace) = heat.paces.get(coronet_key) {
   226→            if let Some(tack) = pace.tacks.first() {
   227→                match tack.state {
   228→                    PaceState::Rough | PaceState::Bridled => {
   229→                        pace_coronet = Some(coronet_key.clone());
   230→                        pace_silks = Some(tack.silks.clone());
   231→                        pace_state = Some(match tack.state {
   232→                            PaceState::Rough => "rough".to_string(),
   233→                            PaceState::Bridled => "bridled".to_string(),
   234→                            _ => unreachable!(),
   235→                        });
   236→                        spec = Some(tack.text.clone());
   237→                        if tack.state == PaceState::Bridled {
   238→                            direction = tack.direction.clone();
   239→                        }
   240→                        break;
   241→                    }
   242→                    _ => continue,
   243→                }
   244→            }
   245→        }
   246→    }
   247→
   248→    // Determine heat status string
   249→    let status_str = match heat.status {
   250→        HeatStatus::Racing => "racing",
   251→        HeatStatus::Stabled => "stabled",
   252→        HeatStatus::Retired => "retired",
   253→    };
   254→
   255→    // Output plain text format
   256→    println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   257→    println!("Paddock: {}", heat.paddock_file);
   258→    println!();
   259→    println!("Paddock-content:");
   260→    for line in paddock_content.lines() {
   261→        println!("  {}", line);
   262→    }
   263→    println!();
   264→
   265→    if let Some(coronet) = pace_coronet {
   266→        if let Some(silks) = pace_silks {
   267→            if let Some(state) = pace_state {
   268→                println!("Next: {} ({}) [{}]", silks, coronet, state);
   269→                println!();
   270→                if let Some(spec_text) = spec {
   271→                    println!("Spec:");
   272→                    for line in spec_text.lines() {
   273→                        println!("  {}", line);
   274→                    }
   275→                    println!();
   276→                }
   277→                if let Some(dir_text) = direction {
   278→                    println!("Direction:");
   279→                    for line in dir_text.lines() {
   280→                        println!("  {}", line);
   281→                    }
   282→                    println!();
   283→                }
   284→            }
   285→        }
   286→    }
   287→
   288→    // Output recent work table
   289→    if !recent_work.is_empty() {
   290→        println!("Recent-work:");
   291→
   292→        let mut table = jjrp_Table::jjrp_new(vec![
   293→            jjrp_Column::new("Timestamp", jjrp_Align::Left),
   294→            jjrp_Column::new("Commit", jjrp_Align::Left),
   295→            jjrp_Column::new("[A]", jjrp_Align::Left),
   296→            jjrp_Column::new("Identity", jjrp_Align::Left),
   297→            jjrp_Column::new("Subject", jjrp_Align::Left),
   298→        ]);
   299→
   300→        // Measure all rows to compute column widths
   301→        for entry in &recent_work {
   302→            let action_str = entry.action.as_ref().map(|a| format!("[{}]", a)).unwrap_or_else(|| "   ".to_string());
   303→            let identity_str = if let Some(ref coronet) = entry.coronet {
   304→                coronet.clone()
   305→            } else {
   306→                heat_key.clone()
   307→            };
   308→            table.jjrp_measure(&[
   309→                &entry.timestamp,
   310→                &entry.commit,
   311→                &action_str,
   312→                &identity_str,
   313→                &entry.subject,
   314→            ]);
   315→        }
   316→
   317→        // Print header and separator
   318→        table.jjrp_print_header();
   319→        table.jjrp_print_separator();
   320→
   321→        // Print data rows
   322→        for entry in &recent_work {
   323→            let action_str = entry.action.as_ref().map(|a| format!("[{}]", a)).unwrap_or_else(|| "   ".to_string());
   324→            let identity_str = if let Some(ref coronet) = entry.coronet {
   325→                coronet.clone()
   326→            } else {
   327→                heat_key.clone()
   328→            };
   329→            table.jjrp_print_row(&[
   330→                &entry.timestamp,
   331→                &entry.commit,
   332→                &action_str,
   333→                &identity_str,
   334→                &entry.subject,
   335→            ]);
   336→        }
   337→    }
   338→
   339→    0
   340→}
   341→
   342→// ============================================================================
   343→// Parade - Display comprehensive Heat status for project review
   344→// ============================================================================
   345→
   346→/// Arguments for parade command
   347→#[derive(Debug)]
   348→pub struct jjrq_ParadeArgs {
   349→    pub file: std::path::PathBuf,
   350→    pub target: String,
   351→    pub full: bool,
   352→    pub remaining: bool,
   353→}
   354→
   355→/// Run the parade command - display comprehensive Heat status
   356→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   357→    let gallops = match Gallops::jjrg_load(&args.file) {
   358→        Ok(g) => g,
   359→        Err(e) => {
   360→            eprintln!("jjx_parade: error: {}", e);
   361→            return 1;
   362→        }
   363→    };
   364→
   365→    // Determine target type by length
   366→    let target_str = args.target.strip_prefix('₢').or_else(|| args.target.strip_prefix('₣')).unwrap_or(&args.target);
   367→
   368→    if target_str.len() == 5 {
   369→        // Coronet - pace view
   370→        let coronet = match Coronet::jjrf_parse(&args.target) {
   371→            Ok(c) => c,
   372→            Err(e) => {
   373→                eprintln!("jjx_parade: error: {}", e);
   374→                return 1;
   375→            }
   376→        };
   377→
   378→        // Extract parent firemark
   379→        let firemark = coronet.jjrf_parent_firemark();
   380→        let heat_key = firemark.jjrf_display();
   381→        let heat = match gallops.heats.get(&heat_key) {
   382→            Some(h) => h,
   383→            None => {
   384→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   385→                return 1;
   386→            }
   387→        };
   388→
   389→        // Find pace
   390→        let coronet_key = coronet.jjrf_display();
   391→        let pace = match heat.paces.get(&coronet_key) {
   392→            Some(p) => p,
   393→            None => {
   394→                eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
   395→                return 1;
   396→            }
   397→        };
   398→
   399→        // Display tack history - iterate in reverse order (oldest first)
   400→        if !pace.tacks.is_empty() {
   401→            // Print header with current state from tacks[0]
   402→            let current_tack = &pace.tacks[0];
   403→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
   404→            println!("Heat: {}", heat_key);
   405→            println!();
   406→
   407→            // Iterate tacks in reverse order (oldest first)
   408→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
   409→                let state_str = zjjrq_pace_state_str(&tack.state);
   410→                let commit_str = if tack.commit == "0000000" {
   411→                    "(no commit)".to_string()
   412→                } else {
   413→                    tack.commit.clone()
   414→                };
   415→
   416→                println!("[{}] {} ({})", index, state_str, commit_str);
   417→                println!("    Silks: {}", tack.silks);
   418→                if let Some(ref direction) = tack.direction {
   419→                    println!("    Direction: {}", direction);
   420→                }
   421→                println!();
   422→                // Indent spec text
   423→                for line in tack.text.lines() {
   424→                    println!("    {}", line);
   425→                }
   426→                println!();
   427→            }
   428→        }
   429→    } else if target_str.len() == 2 {
   430→        // Firemark - heat view
   431→        let firemark = match Firemark::jjrf_parse(&args.target) {
   432→            Ok(fm) => fm,
   433→            Err(e) => {
   434→                eprintln!("jjx_parade: error: {}", e);
   435→                return 1;
   436→            }
   437→        };
   438→
   439→        let heat_key = firemark.jjrf_display();
   440→        let heat = match gallops.heats.get(&heat_key) {
   441→            Some(h) => h,
   442→            None => {
   443→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   444→                return 1;
   445→            }
   446→        };
   447→
   448→        if args.full {
   449→            // Full view: paddock + all specs
   450→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   451→                Ok(content) => content,
   452→                Err(e) => {
   453→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   454→                    return 1;
   455→                }
   456→            };
   457→
   458→            let status_str = match heat.status {
   459→                HeatStatus::Racing => "racing",
   460→                HeatStatus::Stabled => "stabled",
   461→                HeatStatus::Retired => "retired",
   462→            };
   463→
   464→            println!("Heat: {} ({})", heat.silks, heat_key);
   465→            println!("Status: {}", status_str);
   466→            println!("Created: {}", heat.creation_time);
   467→            println!();
   468→            println!("## Paddock");
   469→            println!();
   470→            println!("{}", paddock_content);
   471→            println!();
   472→            println!("## Paces");
   473→            println!();
   474→
   475→            for coronet_key in &heat.order {
   476→                if let Some(pace) = heat.paces.get(coronet_key) {
   477→                    if let Some(tack) = pace.tacks.first() {
   478→                        // Skip complete/abandoned if --remaining
   479→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   480→                            continue;
   481→                        }
   482→                        let state_str = zjjrq_pace_state_str(&tack.state);
   483→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   484→                        println!();
   485→                        println!("{}", tack.text);
   486→                        if let Some(ref direction) = tack.direction {
   487→                            println!();
   488→                            println!("**Direction:** {}", direction);
   489→                        }
   490→                        println!();
   491→                    }
   492→                }
   493→            }
   494→        } else {
   495→            // List view: numbered paces
   496→            // If --remaining, output markdown format
   497→            if args.remaining {
   498→                let mut complete_count = 0;
   499→                let mut abandoned_count = 0;
   500→                let mut rough_count = 0;
   501→                let mut bridled_count = 0;
   502→                let mut remaining_paces: Vec<(&String, &crate::jjrg_gallops::jjrg_Pace)> = Vec::new();
   503→                let mut first_remaining_pace: Option<(&String, &crate::jjrg_gallops::jjrg_Pace)> = None;
   504→
   505→                for coronet_key in &heat.order {
   506→                    if let Some(pace) = heat.paces.get(coronet_key) {
   507→                        if let Some(tack) = pace.tacks.first() {
   508→                            match tack.state {
   509→                                PaceState::Complete => complete_count += 1,
   510→                                PaceState::Abandoned => abandoned_count += 1,
   511→                                PaceState::Rough => {
   512→                                    rough_count += 1;
   513→                                    remaining_paces.push((coronet_key, pace));
   514→                                    if first_remaining_pace.is_none() {
   515→                                        first_remaining_pace = Some((coronet_key, pace));
   516→                                    }
   517→                                }
   518→                                PaceState::Bridled => {
   519→                                    bridled_count += 1;
   520→                                    remaining_paces.push((coronet_key, pace));
   521→                                    if first_remaining_pace.is_none() {
   522→                                        first_remaining_pace = Some((coronet_key, pace));
   523→                                    }
   524→                                }
   525→                            }
   526→                        }
   527→                    }
   528→                }
   529→
   530→                let status_str = match heat.status {
   531→                    HeatStatus::Racing => "racing",
   532→                    HeatStatus::Stabled => "stabled",
   533→                    HeatStatus::Retired => "retired",
   534→                };
   535→
   536→                let remaining_count = rough_count + bridled_count;
   537→
   538→                // Header line with heat info
   539→                println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   540→                println!("Progress: {} complete | {} abandoned | {} remaining ({} rough, {} bridled)",
   541→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
   542→                println!();
   543→
   544→                // Table with remaining paces
   545→                if !remaining_paces.is_empty() {
   546→                    // Set up table with column definitions
   547→                    let mut table = jjrp_Table::jjrp_new(vec![
   548→                        jjrp_Column::new("No", jjrp_Align::Right),
   549→                        jjrp_Column::new("State", jjrp_Align::Left),
   550→                        jjrp_Column::new("Pace", jjrp_Align::Left),
   551→                        jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   552→                    ]);
   553→
   554→                    // Measure all rows to compute column widths
   555→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
   556→                        if let Some(tack) = pace.tacks.first() {
   557→                            let state_str = zjjrq_pace_state_str(&tack.state);
   558→                            table.jjrp_measure(&[
   559→                                &(idx + 1).to_string(),
   560→                                state_str,
   561→                                &tack.silks,
   562→                                coronet_key,
   563→                            ]);
   564→                        }
   565→                    }
   566→
   567→                    // Print header and separator
   568→                    table.jjrp_print_header();
   569→                    table.jjrp_print_separator();
   570→
   571→                    // Print data rows
   572→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
   573→                        if let Some(tack) = pace.tacks.first() {
   574→                            let state_str = zjjrq_pace_state_str(&tack.state);
   575→                            table.jjrp_print_row(&[
   576→                                &(idx + 1).to_string(),
   577→                                state_str,
   578→                                &tack.silks,
   579→                                coronet_key,
   580→                            ]);
   581→                        }
   582→                    }
   583→                    println!();
   584→                }
   585→
   586→                // Next up callout
   587→                if let Some((coronet_key, pace)) = first_remaining_pace {
   588→                    if let Some(tack) = pace.tacks.first() {
   589→                        let state_str = zjjrq_pace_state_str(&tack.state);
   590→                        println!("Next: {} ({}) [{}]", tack.silks, coronet_key, state_str);
   591→                    }
   592→                }
   593→            } else {
   594→                // Column-justified list view (all paces)
   595→                // Set up table with column definitions
   596→                let mut table = jjrp_Table::jjrp_new(vec![
   597→                    jjrp_Column::new("No", jjrp_Align::Right),
   598→                    jjrp_Column::new("State", jjrp_Align::Left),
   599→                    jjrp_Column::new("Pace", jjrp_Align::Left),
   600→                    jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   601→                ]);
   602→
   603→                // Measure all rows to compute column widths
   604→                let mut num = 0;
   605→                for coronet_key in &heat.order {
   606→                    if let Some(pace) = heat.paces.get(coronet_key) {
   607→                        if let Some(tack) = pace.tacks.first() {
   608→                            num += 1;
   609→                            let state_str = zjjrq_pace_state_str(&tack.state);
   610→                            table.jjrp_measure(&[
   611→                                &num.to_string(),
   612→                                state_str,
   613→                                &tack.silks,
   614→                                coronet_key,
   615→                            ]);
   616→                        }
   617→                    }
   618→                }
   619→
   620→                // Print header and separator
   621→                table.jjrp_print_header();
   622→                table.jjrp_print_separator();
   623→
   624→                // Print data rows
   625→                let mut num = 0;
   626→                for coronet_key in &heat.order {
   627→                    if let Some(pace) = heat.paces.get(coronet_key) {
   628→                        if let Some(tack) = pace.tacks.first() {
   629→                            num += 1;
   630→                            let state_str = zjjrq_pace_state_str(&tack.state);
   631→                            table.jjrp_print_row(&[
   632→                                &num.to_string(),
   633→                                state_str,
   634→                                &tack.silks,
   635→                                coronet_key,
   636→                            ]);
   637→                        }
   638→                    }
   639→                }
   640→            }
   641→        }
   642→    } else {
   643→        eprintln!("jjx_parade: error: target must be Firemark (2 chars) or Coronet (5 chars), got {} chars", target_str.len());
   644→        return 1;
   645→    }
   646→
   647→    0
   648→}
