   650→/// Helper to convert PaceState to display string
   651→fn zjjrq_pace_state_str(state: &PaceState) -> &'static str {
   652→    match state {
   653→        PaceState::Rough => "rough",
   654→        PaceState::Bridled => "bridled",
   655→        PaceState::Complete => "complete",
   656→        PaceState::Abandoned => "abandoned",
   657→    }
   658→}
