   661→// Scout - Search across heats and paces with regex
   662→// ============================================================================
   663→
   664→/// Arguments for scout command
   665→#[derive(Debug)]
   666→pub struct jjrq_ScoutArgs {
   667→    pub file: std::path::PathBuf,
   668→    pub pattern: String,
   669→    pub actionable: bool,
   670→}
   671→
   672→/// Run the scout command - regex search across heats/paces
   673→pub fn jjrq_run_scout(args: jjrq_ScoutArgs) -> i32 {
   674→    use regex::RegexBuilder;
   675→
   676→    let gallops = match Gallops::jjrg_load(&args.file) {
   677→        Ok(g) => g,
   678→        Err(e) => {
   679→            eprintln!("jjx_scout: error: {}", e);
   680→            return 1;
   681→        }
   682→    };
   683→
   684→    // Build case-insensitive regex
   685→    let re = match RegexBuilder::new(&args.pattern)
   686→        .case_insensitive(true)
   687→        .build()
   688→    {
   689→        Ok(r) => r,
   690→        Err(e) => {
   691→            eprintln!("jjx_scout: error: invalid regex pattern: {}", e);
   692→            return 1;
   693→        }
   694→    };
   695→
   696→    // Track which heats have matches (for group headers)
   697→    let mut current_heat_key: Option<String> = None;
   698→
   699→    // Iterate all heats (racing, stabled, retired)
   700→    for (heat_key, heat) in &gallops.heats {
   701→        // Search each pace in order
   702→        for coronet_key in &heat.order {
   703→            if let Some(pace) = heat.paces.get(coronet_key) {
   704→                if let Some(tack) = pace.tacks.first() {
   705→                    // Apply actionable filter if requested
   706→                    if args.actionable {
   707→                        match tack.state {
   708→                            PaceState::Rough | PaceState::Bridled => {},
   709→                            _ => continue,
   710→                        }
   711→                    }
   712→
   713→                    // Search: silks, spec (tack text), direction, paddock content
   714→                    // Use owned strings to avoid lifetime issues
   715→                    let mut match_result: Option<(String, String)> = None;
   716→
   717→                    if re.is_match(&tack.silks) {
   718→                        match_result = Some(("silks".to_string(), tack.silks.clone()));
   719→                    } else if re.is_match(&tack.text) {
   720→                        match_result = Some(("spec".to_string(), tack.text.clone()));
   721→                    } else if let Some(ref direction) = tack.direction {
   722→                        if re.is_match(direction) {
   723→                            match_result = Some(("direction".to_string(), direction.clone()));
   724→                        }
   725→                    } else {
   726→                        // Search paddock content
   727→                        let paddock_path = std::path::Path::new(&heat.paddock_file);
   728→                        if let Ok(content) = fs::read_to_string(paddock_path) {
   729→                            if re.is_match(&content) {
   730→                                match_result = Some(("paddock".to_string(), content));
   731→                            }
   732→                        }
   733→                    }
   734→
   735→                    // If we found a match, output it
   736→                    if let Some((field_name, field_content)) = match_result {
   737→                        // Print heat header if this is a new heat
   738→                        if current_heat_key.as_ref() != Some(heat_key) {
   739→                            println!("{} {}", heat_key, heat.silks);
   740→                            current_heat_key = Some(heat_key.clone());
   741→                        }
   742→
   743→                        // Print pace line
   744→                        let state_str = zjjrq_pace_state_str(&tack.state);
   745→                        println!("  {} [{}] {}", coronet_key, state_str, tack.silks);
   746→
   747→                        // Print match line with context (extract ~60 chars around match)
   748→                        let match_excerpt = zjjrq_extract_match_context(&field_content, &re);
   749→                        println!("    {}: {}", field_name, match_excerpt);
   750→                    }
   751→                }
   752→            }
   753→        }
   754→    }
   755→
   756→    0
   757→}
   758→
   759→/// Extract context around the first regex match in content
   760→fn zjjrq_extract_match_context(content: &str, re: &regex::Regex) -> String {
   761→    if let Some(mat) = re.find(content) {
   762→        let start = mat.start();
   763→        let end = mat.end();
   764→
   765→        // Find context window (30 chars before, 30 chars after)
   766→        let context_before = 30;
   767→        let context_after = 30;
   768→
   769→        let window_start = start.saturating_sub(context_before);
   770→        let window_end = (end + context_after).min(content.len());
   771→
   772→        let mut excerpt = String::new();
   773→        if window_start > 0 {
   774→            excerpt.push_str("...");
   775→        }
   776→        excerpt.push_str(&content[window_start..window_end]);
   777→        if window_end < content.len() {
   778→            excerpt.push_str("...");
   779→        }
   780→
   781→        // Replace newlines with spaces for single-line display
   782→        excerpt.replace('\n', " ").replace('\r', "")
   783→    } else {
   784→        // Shouldn't happen, but fallback to truncated content
   785→        let truncated = content.chars().take(60).collect::<String>();
   786→        if content.len() > 60 {
   787→            format!("{}...", truncated)
   788→        } else {
   789→            truncated
   790→        }
   791→    }
   792→}
